import xml.etree.ElementTree as ET
import os
from typing import Dict, Any

def parse_xml_config(file_path: str) -> Dict[str, Any]:
    """
    Parse an XML configuration file and return settings as a dictionary.
    
    Args:
        file_path (str): Path to the XML configuration file
        
    Returns:
        Dict[str, Any]: Configuration settings as dictionary
        
    Raises:
        FileNotFoundError: If the file does not exist
        ET.ParseError: If the XML is malformed
        ValueError: If the file path is invalid
    """
    # Validate file path
    if not isinstance(file_path, str):
        raise ValueError("File path must be a string")
    
    if not file_path:
        raise ValueError("File path cannot be empty")
    
    # Check if file exists
    if not os.path.exists(file_path):
        raise FileNotFoundError(f"Configuration file not found: {file_path}")
    
    # Check if file is readable
    if not os.access(file_path, os.R_OK):
        raise PermissionError(f"Permission denied to read configuration file: {file_path}")
    
    try:
        # Parse XML with secure configuration
        tree = ET.parse(file_path)
        root = tree.getroot()
        
        # Build configuration dictionary
        config = {}
        
        # Handle root element attributes
        if root.attrib:
            config['@attributes'] = root.attrib
        
        # Process child elements
        for child in root:
            if len(child) == 0:  # Leaf element
                if child.text is not None:
                    config[child.tag] = child.text.strip() if child.text.strip() else ""
                else:
                    config[child.tag] = ""
            else:  # Element with children
                config[child.tag] = parse_element(child)
        
        return config
        
    except ET.ParseError as e:
        raise ET.ParseError(f"Invalid XML format in configuration file: {e}")

def parse_element(element) -> Dict[str, Any]:
    """Recursively parse XML element and its children."""
    result = {}
    
    # Handle element attributes
    if element.attrib:
        result['@attributes'] = element.attrib
    
    # Handle child elements
    children = list(element)
    if children:
        for child in children:
            child_data = parse_element(child)
            if child.tag in result:
                # Handle multiple elements with same tag
                if not isinstance(result[child.tag], list):
                    result[child.tag] = [result[child.tag]]
                result[child.tag].append(child_data)
            else:
                result[child.tag] = child_data
    else:
        # Leaf element with text content
        if element.text is not None:
            result['#text'] = element.text.strip() if element.text.strip() else ""
        else:
            result['#text'] = ""
    
    return result